SELECT AVG(precipitation) AS average_precipitation
FROM precipitations
WHERE data_id = 1;

SELECT AVG(visibility) AS average_visibility
FROM visibility
WHERE data_id = 1;

SELECT AVG(pressure) AS average_pressure
FROM pressure
WHERE timestamp = '2023-01-01 00:00:00';

SELECT pressure
FROM pressure
WHERE data_id = 0;

SELECT AVG(pressure) AS average_pressure, unit
FROM pressure
WHERE data_id = 0;

SELECT wind_speed
FROM wind_speeds
WHERE timestamp = '2023-01-01 00:00:00';
